code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Badge, icon } from 'decantr/components';

code.example:
function ReputationBadge({ score, trusted }) {
  const level = trusted ? { icon: 'shield-check', label: 'Trusted', variant: 'success' }
    : score >= 25 ? { icon: 'trending-up', label: 'Rising', variant: 'warning' }
    : { icon: 'circle', label: 'New', variant: 'secondary' };

  return Badge({ variant: level.variant, size: 'sm' },
    icon(level.icon, { size: '0.75rem' }),
    ` ${score} · ${level.label}`
  );
}

