code.example:
function ReputationBadgeLarge({ score, trusted, stats }) {
  const { div, span, h3, p } = tags;
  const progress = Math.min(score / 50 * 100, 100);

  return div({ class: css('_flex _col _gap3 _p4 _border _bordermuted/20 _r3') },
    div({ class: css('_flex _aic _gap3') },
      div({ class: css('_w10 _h10 _flex _center _rfull _bgprimary/15') },
        icon(trusted ? 'shield-check' : 'star', { size: '1.25rem', class: css('_fgprimary') })
      ),
      div({ class: css('_flex _col') },
        h3({ class: css('_heading3') }, `${score}`),
        span({ class: css('_textxs _fgmuted') }, trusted ? 'Trusted Contributor' : 'Reputation Score')
      )
    ),
    div({ class: css('_flex _col _gap1') },
      div({ class: css('_flex _jcsb _textxs _fgmuted') },
        span({}, 'Trust threshold'),
        span({}, `${score}/50`)
      ),
      div({ class: css('_wfull _h2 _bgmuted/20 _rfull _overflow[hidden]') },
        div({ class: css('_hfull _bgprimary _rfull'), style: `width: ${progress}%` })
      )
    ),
    div({ class: css('_flex _gap4 _textxs') },
      div({ class: css('_flex _aic _gap1') },
        icon('check-circle', { size: '0.75rem', class: css('_fgsuccess') }),
        span({}, `${stats?.approved || 0} approved`)
      ),
      div({ class: css('_flex _aic _gap1') },
        icon('x-circle', { size: '0.75rem', class: css('_fgdestructive') }),
        span({}, `${stats?.rejected || 0} rejected`)
      ),
      div({ class: css('_flex _aic _gap1') },
        icon('award', { size: '0.75rem', class: css('_fgwarning') }),
        span({}, `${stats?.featured || 0} featured`)
      )
    )
  );
}

function ReputationBadgeCompact({ score, trusted }) {
  const { span } = tags;
  const dotColor = trusted ? '_bgsuccess' : score >= 25 ? '_bgwarning' : '_bgmuted';

  return span({ class: css('_inline-flex _aic _gap1') },
    span({ class: css(`_w2 _h2 _rfull ${dotColor}`) }),
    span({ class: css('_textxs _fgmuted') }, `${score}`)
  );
}

